510→/// Validate officium directory exists and touch heartbeat.
511→fn zjjrm_validate_officium(officium: &str) -> Result<(), String> {
512→    let bare_id = officium.trim_start_matches(OFFICIUM_SUN_PREFIX);
513→    let exchange = PathBuf::from(OFFICIA_DIR).join(bare_id);
514→    if !exchange.is_dir() {
515→        return Err(format!(
516→            "Officium directory not found: {}. Call jjx_open to create a new officium.",
517→            bare_id
518→        ));
519→    }
520→    // Touch heartbeat
521→    std::fs::write(exchange.join(HEARTBEAT_FILE), b"").ok();
522→    Ok(())
523→}
