525→/// Resolve officium ID to gazette input file path (agent → server).
526→fn zjjrm_gazette_in_path(officium: &str) -> std::path::PathBuf {
527→    let bare_id = officium.trim_start_matches(OFFICIUM_SUN_PREFIX);
528→    PathBuf::from(OFFICIA_DIR).join(bare_id).join(GAZETTE_IN_FILE)
529→}
