537→/// Handle jjx_open: create a new officium.
538→async fn zjjrm_handle_open() -> Result<CallToolResult, McpError> {
539→    let cn = JJRM_CMD_NAME_OPEN;
540→    let mut output = vvc::vvco_Output::buffer();
541→
542→    // Disk space guard — block before any state changes
543→    match crate::jjrdk_diskcheck::jjrdk_check_disk_space() {
544→        Ok(survey) => vvco_out!(output, "{}", survey),
545→        Err(msg) => return Ok(CallToolResult::error(vec![Content::text(msg)])),
546→    }
547→
548→    let officia = PathBuf::from(OFFICIA_DIR);
549→    if let Err(e) = std::fs::create_dir_all(&officia) {
550→        return Ok(CallToolResult::error(vec![Content::text(
551→            format!("{}: error creating officia dir: {}", cn, e),
552→        )]));
553→    }
554→
555→    // Exsanguinate stale officia before creating new one
556→    let (reaped, active) = zjjrm_exsanguinate(&officia);
557→
558→    // Generate officium ID and atomically claim the exchange directory.
559→    // create_dir (not create_dir_all) fails with AlreadyExists if another
560→    // session raced to the same ID — retry with next autonumber.
561→    let today = chrono::Local::now().format("%y%m%d").to_string();
562→    let (id, exchange) = loop {
563→        let candidate = zjjrm_generate_officium_id(&officia, &today);
564→        let path = officia.join(&candidate);
565→        match std::fs::create_dir(&path) {
566→            Ok(()) => break (candidate, path),
567→            Err(e) if e.kind() == std::io::ErrorKind::AlreadyExists => continue,
568→            Err(e) => {
569→                return Ok(CallToolResult::error(vec![Content::text(
570→                    format!("{}: error creating exchange dir: {}", cn, e),
571→                )]));
572→            }
573→        }
574→    };
575→    // No gazette files created at open — they are ephemeral, single-MCP-call lifetime.
576→    std::fs::write(exchange.join(HEARTBEAT_FILE), b"").ok();
577→
578→    // Daily probe: run vvcp_probe if .probe_date doesn't match today
579→    let probe_date_path = officia.join(PROBE_DATE_FILE);
580→    let probe_data = if zjjrm_needs_probe(&probe_date_path, &today) {
581→        match vvc::vvcp_probe().await {
582→            Ok(data) => {
583→                std::fs::write(&probe_date_path, &today).ok();
584→                Some(data)
585→            }
586→            Err(e) => {
587→                eprintln!("{}: probe warning: {}", cn, e);
588→                None
589→            }
590→        }
591→    } else {
592→        None
593→    };
594→
595→    // Invitatory commit: jjb:BRAND::i: OFFICIUM <id>
596→    let brand = vvc::vvcc_get_brand();
597→    let subject = format!("OFFICIUM {}", id);
598→    let action = crate::jjrnm_markers::JJRNM_INVITATORY.to_string();
599→    let message = vvc::vvcc_format_branded(
600→        crate::jjrn_notch::JJRN_COMMIT_PREFIX,
601→        &brand,
602→        "",
603→        &action,
604→        &subject,
605→        probe_data.as_deref(),
606→    );
607→
608→    let commit_args = vvc::vvcc_CommitArgs {
609→        prefix: None,
610→        message: Some(message),
611→        allow_empty: true,
612→        no_stage: true,
613→        size_limit: vvc::VVCG_SIZE_LIMIT,
614→        warn_limit: vvc::VVCG_WARN_LIMIT,
615→    };
616→
617→    match vvc::vvcc_CommitLock::vvcc_acquire() {
618→        Ok(lock) => {
619→            let mut commit_output = vvc::vvco_Output::buffer();
620→            if let Err(e) = lock.vvcc_commit(&commit_args, &mut commit_output) {
621→                return Ok(CallToolResult::error(vec![Content::text(
622→                    format!("{}: invitatory commit error: {}", cn, e),
623→                )]));
624→            }
625→        }
626→        Err(e) => {
627→            return Ok(CallToolResult::error(vec![Content::text(
628→                format!("{}: lock error: {}", cn, e),
629→            )]));
630→        }
631→    };
632→
633→    if reaped > 0 || active > 0 {
634→        vvco_out!(output, "Exsanguination: {} active, {} reaped", active, reaped);
635→    }
636→    vvco_out!(output, "{}{}", OFFICIUM_SUN_PREFIX, id);
637→    Ok(CallToolResult::success(vec![Content::text(output.vvco_finish())]))
638→}
