645→/// Extract model tier from verbatim model ID string.
646→/// Returns "opus", "sonnet", "haiku", or "unknown".
647→fn zjjrm_extract_tier(model: &str) -> &'static str {
648→    let lower = model.to_ascii_lowercase();
649→    if lower.contains("opus") {
650→        "opus"
651→    } else if lower.contains("sonnet") {
652→        "sonnet"
653→    } else if lower.contains("haiku") {
654→        "haiku"
655→    } else {
656→        "unknown"
657→    }
658→}
659→
660→/// Gate check: require opus-tier model. Returns Err with diagnostic on failure.
661→fn zjjrm_check_model_gate(model: &str) -> Result<(), String> {
662→    let tier = zjjrm_extract_tier(model);
663→    if tier == "opus" {
664→        return Ok(());
665→    }
666→    Err(format!(
667→        "MODEL GATE — this command requires opus.\n\n  Received model: {}\n  Extracted tier: {}\n\nJob Jockey commands currently require an opus-tier model.",
668→        model, tier
669→    ))
670→}
