673→// MCP Server
674→// ============================================================================
675→
676→#[derive(Debug, Clone)]
677→pub struct jjrm_McpServer {
678→    tool_router: ToolRouter<Self>,
679→}
680→
681→#[tool_router]
682→impl jjrm_McpServer {
683→    pub fn jjrm_new() -> Self {
684→        Self {
685→            tool_router: Self::tool_router(),
686→        }
687→    }
688→
689→    #[tool(name = "jjx", description = "Job Jockey Kit - MCP tools for project initiative management")]
690→    async fn jjx(&self, Parameters(p): Parameters<jjrm_JjxParams>) -> Result<CallToolResult, McpError> {
691→        let cmd = p.command.as_str();
692→
693→        // Model gate: required on all commands, checked first
694→        if let Err(msg) = zjjrm_check_model_gate(&p.model) {
695→            return Ok(CallToolResult::error(vec![Content::text(
696→                format!("jjx {}: {}", cmd, msg),
697→            )]));
698→        }
699→        eprintln!("jjx {}: model={}", cmd, p.model);
700→
701→        // jjx_open creates the officium — handle before officium validation
702→        if cmd == JJRM_CMD_NAME_OPEN {
703→            return zjjrm_handle_open().await;
704→        }
705→
706→        // Officium envelope: required on all commands except jjx_open
707→        match p.officium {
708→            Some(ref officium) => {
709→                if let Err(e) = zjjrm_validate_officium(officium) {
710→                    return Ok(CallToolResult::error(vec![Content::text(
711→                        format!("jjx {}: {}", cmd, e),
712→                    )]));
713→                }
714→            }
715→            None => {
716→                return Ok(CallToolResult::error(vec![Content::text(
717→                    format!("jjx {}: officium parameter required. Call jjx_open first to create an officium.", cmd),
718→                )]));
719→            }
720→        }
721→        // Universal entry rule: read+delete gazette_in, delete gazette_out.
722→        // Gazette content has single-MCP-call lifetime.
723→        let officium_id = p.officium.as_ref().unwrap();
724→        let gazette_in_path = zjjrm_gazette_in_path(officium_id);
725→        let gazette_out_path = zjjrm_gazette_out_path(officium_id);
726→        let gazette_in_content: Option<String> = {
727→            let content = std::fs::read_to_string(&gazette_in_path).ok();
728→            let _ = std::fs::remove_file(&gazette_in_path);
729→            content.filter(|s| !s.trim().is_empty())
730→        };
731→        let _ = std::fs::remove_file(&gazette_out_path);
732→
733→        let v = match p.params {
734→            serde_json::Value::String(ref s) => {
735→                serde_json::from_str(s).unwrap_or(p.params)
736→            }
737→            other => other,
738→        };
739→
740→        macro_rules! deser {
741→            ($t:ty) => {
742→                match serde_json::from_value::<$t>(v) {
743→                    Ok(p) => p,
744→                    Err(e) => return jjrm_deser_error(cmd, e),
745→                }
746→            }
747→        }
748→
749→
750→        match cmd {
751→            JJRM_CMD_NAME_RECORD => {
752→                let p = deser!(jjrm_RecordParams);
753→                jjrm_result(jjrnc_run_notch(jjrnc_NotchArgs {
754→                    identity: p.identity,
755→                    files: p.files,
756→                    size_limit: p.size_limit,
757→                    intent: p.intent,
758→                }))
759→            }
760→            JJRM_CMD_NAME_LOG => {
761→                let p = deser!(jjrm_LogParams);
762→                jjrm_result(jjrrn_run_rein(jjrrn_ReinArgs {
763→                    firemark: p.firemark,
764→                    limit: p.limit.unwrap_or(50),
765→                }))
766→            }
767→            JJRM_CMD_NAME_VALIDATE => {
768→                let _p = deser!(jjrm_ValidateParams);
769→                jjrm_result(jjrvl_run_validate(jjrvl_ValidateArgs {
770→                    file: gallops_pathbuf(),
771→                }))
772→            }
773→            JJRM_CMD_NAME_LIST => {
774→                let p = deser!(jjrm_ListParams);
775→                jjrm_result(jjrmu_run_muster(jjrmu_MusterArgs {
776→                    file: gallops_pathbuf(),
777→                    status: p.status,
778→                }).await)
779→            }
